document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("selectedPeriod");e&&(e.innerHTML='<span class="header-app-style-other">Περίοδος : </span>',setTimeout(()=>{(async()=>{try{const t=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,n=await fetch("/api/periodInUse",{method:"GET",headers:{"Content-Type":"application/json",...t&&{"CSRF-Token":t}},credentials:"include"});if(401===n.status)return void(e.innerHTML='<span class="header-app-style-other">Περίοδος : </span>');if(!n.ok)throw new Error(`HTTP ${n.status}: ${n.statusText}`);const s=n.headers.get("content-type");if(!s||!s.includes("application/json"))return;const a=await n.text();if(!a||""===a.trim())return;const r=JSON.parse(a);r&&r.periodInUseDescr?e.innerHTML=`<span class="header-app-style-other">Περίοδος : ${r.periodInUseDescr}</span>`:e.innerHTML='<span class="header-app-style-other">Περίοδος : </span>'}catch(t){console.error("Πρόβλημα κατά την εμφάνιση της περιόδου χρήσης:",t),e.innerHTML='<span class="header-app-style-other">Περίοδος : </span>'}})()},100))});